#!/usr/bin/env python3
"""Generate all paper part files for 2026-04-08 arXiv AI daily report."""
import os

DATE = "2026-04-08"
D = f"arxiv-ai/parts/{DATE}"
os.makedirs(D, exist_ok=True)

parts = {}

parts["part02_llm_01.html"] = '<h2 class="section-title llm">🧠 LLM — 纯文本大模型</h2>\n<div class="paper-card" id="p1"><div class="paper-title"><a href="https://arxiv.org/abs/2604.05091">MegaTrain: Full Precision Training of 100B+ Parameter LLMs on a Single GPU</a></div><div class="paper-meta"><span>📅 2026-04-06 | <a href="https://arxiv.org/pdf/2604.05091">PDF</a> | <a href="https://github.com/DLYuanGod/MegaTrain">Code</a></span><span>🏛 University of Notre Dame, Lehigh University</span><span><span class="tag tag-llm">LLM</span> <span class="tag">Training System</span></span></div><h3>背景与动机</h3><p>LLM后训练需全精度加载100B+参数（840GB+持久状态），远超单GPU显存。MegaTrain彻底反转GPU中心范式：CPU主存存储所有持久状态，GPU仅作瞬态计算引擎。</p><h3>核心方法详解</h3><div class="method-module"><h4>① 内存中心架构</h4><p>参数、优化器、梯度全部驻留CPU。前向逐层流式传入GPU，计算后立即释放。模型规模与GPU显存完全解耦：\\(M_{\\text{GPU}} = O(P_{\\max} + N \\cdot A_{\\max} \\cdot L/K)\\)</p></div><div class="method-module"><h4>② 流水线双缓冲</h4><p>三条CUDA流（计算/H2D/D2H）+ 乒乓双缓冲：GPU执行第i层时同时预取i+1层。CUDA事件轻量协调，GPU永不空等。</p></div><div class="method-module"><h4>③ 无状态层模板</h4><p>替代全局autograd图，模板封装kernel但不持有权重指针，Bind动态映射缓冲区视图。消除持久化图元数据。</p></div><div class="method-module"><h4>④ 层连续平铺</h4><p>每层所有状态打包成4KB对齐连续块→单次DMA饱和PCIe（~26GB/s）。CPU端AdamW用AVX-512更新，避免4×数据搬运。</p></div><h3>深度案例</h3><div class="example-box"><strong>单H200 + 1.5TB CPU训练120B MoE</strong><br>GPU端~75GB（双缓冲+激活栈+checkpoint），CPU端全部持久状态。结果：120B成功训练，ZeRO-3在72B时OOM。RTX 3090也可训练14B（30 TFLOPS）。</div><h3>实验结果</h3><table><tr><th>指标</th><th>MegaTrain</th><th>ZeRO-3</th><th>FSDP</th></tr><tr><td>14B TFLOPS (GH200)</td><td class="highlight">264 (1.84×)</td><td>143</td><td>199</td></tr><tr><td>最大可训练规模</td><td class="highlight">120B</td><td>32B OOM</td><td>56B OOM</td></tr><tr><td>14B Accuracy</td><td>92.52%</td><td>92.41%</td><td>—</td></tr><tr><td>512K Context 7B</td><td class="highlight">407 TFLOPS</td><td>—</td><td>—</td></tr></table><h3>消融与讨论</h3><p>双缓冲是关键（移除↓31.3%），28→180层仅降20.1%吞吐。数值精度完全一致。</p><h3>结论与启发</h3><p>训练大模型关键在内存组织而非GPU容量。参数"流过"而非"常驻"，消费级硬件即可训练百亿模型。</p></div>\n'

parts["part03_llm_02.html"] = '<div class="paper-card" id="p2"><div class="paper-title"><a href="https://arxiv.org/abs/2604.05114">π²: Structure-Originated Reasoning Data Improves Long-Context Reasoning</a></div><div class="paper-meta"><span>📅 2026-04-06 | <a href="https://arxiv.org/pdf/2604.05114">PDF</a> | <a href="https://github.com/vt-pi-squared/pi-squared">Code</a></span><span>🏛 Virginia Tech</span><span><span class="tag tag-llm">LLM</span> <span class="tag">Long-Context</span></span></div><h3>背景与动机</h3><p>128K+窗口不自动提升推理能力。π²以Wikipedia表格为结构化起点，经"表格扩展→双路径验证QA→推理轨迹反向翻译"管线生成高质量长上下文推理数据。</p><h3>核心方法详解</h3><div class="method-module"><h4>① 表格收集+合成扩展</h4><p>从Wikipedia提取表格并用LLM添加1-3列外部信息，突破单文档限制和预训练记忆。</p></div><div class="method-module"><h4>② SQL+Python双路径验证</h4><p>多跳推理问题+SQL查询，独立Python方案验证。两者一致才保留。LLM评分复杂度/自包含性/自然性。</p></div><div class="method-module"><h4>③ 推理轨迹反向翻译</h4><p>证据页面+搜索文章→压缩至96K tokens。<strong>严格排除原始表格</strong>，LLM基于非结构化文本生成逐步推理轨迹。</p></div><div class="method-module"><h4>④ 自蒸馏SFT</h4><p>922样本LoRA(r=8) SFT，4×H200仅2.5小时。自蒸馏在Low模式+4.40%（42.35 vs 42.23）。</p></div><h3>深度案例</h3><div class="example-box"><strong>ICPC历史问答</strong>：从多文档中逐年追踪世界冠军→发现2021年MIT夺冠→答案：1次美国队胜。基础模型错答0次。</div><h3>实验结果</h3><table><tr><th>模型</th><th>LongSeal</th><th>OfficeQA</th><th>π²-Bench</th><th>Avg</th></tr><tr><td>gpt-oss-20b base(H)</td><td>52.17</td><td>37.84</td><td>72.57</td><td>48.90</td></tr><tr><td>π²-20B-A3B (H)</td><td class="highlight">64.00</td><td class="highlight">46.58</td><td class="highlight">77.27</td><td class="highlight">53.22</td></tr></table><h3>消融与讨论</h3><p>100样本即可+2.85%。High模式放大收益（LongSeal +11.83）。自蒸馏High模式退化。</p><h3>结论与启发</h3><p>922个高质量样本即可显著提升。"结构化数据→问题→轨迹"管线通用且可扩展。</p></div>\n'

parts["part04_llm_03.html"] = '<div class="paper-card" id="p3"><div class="paper-title"><a href="https://arxiv.org/abs/2604.06169">In-Place Test-Time Training: LLM运行时动态权重适配</a></div><div class="paper-meta"><span>📅 2026-04-07 | <a href="https://arxiv.org/pdf/2604.06169">PDF</a></span><span>🏛 ByteDance Seed, Peking University</span><span><span class="tag tag-llm">LLM</span> <span class="tag tag-whitelist">🏢 ByteDance/Seed</span> <span class="tag">TTT</span></span></div><h3>背景与动机</h3><p>静态范式限制LLM动态适配能力。TTT通过推理时更新权重突破限制，但面临窗口瓶颈和灾难性遗忘。</p><h3>核心方法详解</h3><div class="method-module"><h4>① 选择性层级更新</h4><p>梯度范数选top-k层进行TTT，计算开销从3.2×降至1.4×。</p></div><div class="method-module"><h4>② Fisher正则化防遗忘</h4><p>\\(\\mathcal{L}_{\\text{TTT}} = \\mathcal{L}_{\\text{task}} + \\frac{\\lambda}{2}\\sum_i F_i(\\theta_i - \\theta_i^0)^2\\)，Fisher信息对角近似保护重要权重。</p></div><div class="method-module"><h4>③ 流式上下文消化</h4><p>长上下文分块→每块TTT更新→信息编码进权重→等效窗口从128K扩展到500K+。</p></div><h3>深度案例</h3><div class="example-box"><strong>128K模型处理500K文档</strong>：分4块处理，每块TTT后信息编码进权重，等效5×上下文扩展。</div><h3>实验结果</h3><table><tr><th>方法</th><th>NIAH 128K</th><th>NIAH 256K</th><th>LongBench</th><th>延迟</th></tr><tr><td>Base</td><td>85.2</td><td>43.1</td><td>52.3</td><td>1.0×</td></tr><tr><td class="highlight">IPTTT</td><td class="highlight">92.1</td><td class="highlight">82.3</td><td class="highlight">61.5</td><td>1.4×</td></tr></table><h3>消融与讨论</h3><p>Fisher正则移除→短任务降5.3%。选择性更新3.2×→1.4×。超长上下文(512K+)增益最显著。</p><h3>结论与启发</h3><p>不改架构不重训练，推理时智能更新少量参数即可吸收新信息。为流式对话、长文档理解开辟新方向。</p></div>\n'

parts["part05_llm_04.html"] = '<div class="paper-card" id="p4"><div class="paper-title"><a href="https://arxiv.org/abs/2604.05868">Understanding Performance Gap Between Parallel and Sequential Sampling in Large Reasoning Models</a></div><div class="paper-meta"><span>📅 2026-04-07 | <a href="https://arxiv.org/pdf/2604.05868">PDF</a></span><span>🏛 Google DeepMind, NUS</span><span><span class="tag tag-llm">LLM</span> <span class="tag tag-whitelist">🏢 Google DeepMind</span> <span class="tag">Test-Time Compute</span></span></div><h3>背景与动机</h3><p>大推理模型的并行（多候选投票）vs顺序（更长思考链）策略存在显著性能差距，理论根源不清。</p><h3>核心方法详解</h3><div class="method-module"><h4>① 搜索空间分析</h4><p>顺序≈DFS（深层结构解偏好），并行≈BFS（多浅层解偏好）。</p></div><div class="method-module"><h4>② 条件熵视角</h4><p>顺序通过延长推理链降低\\(H(Y|X,C_t)\\)。边际增益衰减缓慢时顺序占优。</p></div><div class="method-module"><h4>③ 任务特异性实证</h4><p>数学→顺序；常识→并行；代码→接近。混合策略（4×8K+voting）通常最优。</p></div><h3>实验结果</h3><table><tr><th>任务</th><th>并行16×2K</th><th>顺序1×32K</th></tr><tr><td>MATH L5</td><td>62.3</td><td class="highlight">78.1</td></tr><tr><td>AIME</td><td>23.3</td><td class="highlight">40.0</td></tr><tr><td>MMLU-Pro</td><td class="highlight">72.8</td><td>69.5</td></tr></table><h3>结论与启发</h3><p>为inference-time compute分配提供理论指导。32K→64K边际收益快速衰减，存在"有效思考长度"上限。</p></div>\n<div class="paper-card" id="p5"><div class="paper-title"><a href="https://arxiv.org/abs/2604.05273">Beneath the Surface: LLM潜台词理解能力研究</a></div><div class="paper-meta"><span>📅 2026-04-07 | <a href="https://arxiv.org/pdf/2604.05273">PDF</a></span><span>🏛 Google DeepMind</span><span><span class="tag tag-llm">LLM</span> <span class="tag tag-whitelist">🏢 Google DeepMind</span> <span class="tag">Pragmatics</span></span></div><h3>背景与动机</h3><p>人类交流中大量信息通过潜台词传递，但LLM的潜台词能力未被系统研究。构建首个大规模潜台词基准。</p><h3>核心方法详解</h3><div class="method-module"><h4>① 6类潜台词分类</h4><p>讽刺/反讽、暗示、间接请求、礼貌性拒绝、隐含批评、社交暗示。理解+生成双重评估，10位语言学家评分。</p></div><h3>实验结果</h3><table><tr><th>模型</th><th>识别率</th><th>意图F1</th><th>自然度</th></tr><tr><td>GPT-5.4</td><td class="highlight">82.3%</td><td class="highlight">0.79</td><td class="highlight">4.2</td></tr><tr><td>Llama-70B</td><td>62.8%</td><td>0.58</td><td>3.4</td></tr></table><h3>结论与启发</h3><p>讽刺识别最佳(85%+)，隐含批评最差(55-65%)。西方场景>东亚场景，暴露训练偏向。人类93%。对话AI需超越字面层面。</p></div>\n'

parts["part06_rl_01.html"] = '<h2 class="section-title rl">🎯 RL — 强化学习与对齐</h2>\n<div class="paper-card" id="p6"><div class="paper-title"><a href="https://arxiv.org/abs/2604.06159">Target Policy Optimization (TPO)</a></div><div class="paper-meta"><span>📅 2026-04-07 | <a href="https://arxiv.org/pdf/2604.06159">PDF</a> | <a href="https://github.com/JeanKaddour/tpo">Code</a></span><span>🏛 Independent Researcher</span><span><span class="tag tag-rl">RL</span> <span class="tag">RLVR</span></span></div><h3>背景与动机</h3><p>GRPO将概率重分配与优化器机制纠缠，稀疏奖励下脆弱。TPO构建目标分布+交叉熵拟合完全解耦。</p><h3>核心方法详解</h3><div class="method-module"><h4>① 目标分布</h4><p>\\(q_i = \\frac{p_i^{\\text{old}} \\exp(u_i/\\eta)}{\\sum_j p_j^{\\text{old}} \\exp(u_j/\\eta)}\\)，KL正则化改进的闭式解，无需critic。</p></div><div class="method-module"><h4>② 梯度自熄灭</h4><p>\\(\\mathcal{L} = -\\sum q_i \\log p_i^\\theta\\)，梯度\\(= p^\\theta - q\\)→匹配时为零。唯一不动点。GRPO梯度持续存在。</p></div><div class="method-module"><h4>③ 预算分配</h4><p>\\(p_n=0.1\\)时：TPO \\(\\beta=0.73\\) vs DG=0.09, GRPO=0.33。更多预算给困难上下文。</p></div><div class="method-module"><h4>④ 稳定多epoch</h4><p>TPO 1-16 epoch均&lt;2.3% error。GRPO非单调(2ep 37.6%, 16ep 1.1%)。DG多epoch发散。</p></div><h3>深度案例</h3><div class="example-box"><strong>终端奖励 H=10</strong>：90%全失败group→TPO的\\(u=0 \\Rightarrow q=p^{\\text{old}}\\)→首epoch零贡献→自动聚焦稀有信息group。<br>TPO: 7.4% | GRPO: 50.4% | PPO/DG: >95%</div><h3>实验结果</h3><table><tr><th>LLM RLVR</th><th>TPO</th><th>GRPO</th></tr><tr><td>GSM8K</td><td>~87%</td><td>~85%</td></tr><tr><td>Graph Coloring</td><td class="highlight">~0.96</td><td>~0.0 (失败)</td></tr></table><h3>消融与讨论</h3><p>三属性（自熄灭+稳定复用+信号聚焦）相互增强。简单任务差距小，难任务差距巨大。仅测试1.5-1.7B。</p><h3>结论与启发</h3><p>用"构建目标+拟合"替代"标量加权PG"，仅~9行代码。理论清晰，稀疏奖励下优势显著。</p></div>\n'

parts["part07_rl_02.html"] = '<div class="paper-card" id="p7"><div class="paper-title"><a href="https://arxiv.org/abs/2604.05424">PRISM-MCTS: 元认知反思驱动的推理树搜索</a></div><div class="paper-meta"><span>📅 2026-04-07 | <a href="https://arxiv.org/pdf/2604.05424">PDF</a></span><span>🏛 Tencent PCG</span><span><span class="tag tag-rl">RL</span> <span class="tag tag-whitelist">🏢 Tencent</span> <span class="tag">MCTS</span></span></div><h3>背景与动机</h3><p>MCTS将rollout视为独立轨迹→计算冗余。PRISM-MCTS引入启发式/谬误双记忆实现全局信息共享。</p><h3>核心方法详解</h3><div class="method-module"><h4>① 双记忆架构</h4><p>启发式记忆(PRM≥τ_pos)存成功策略；谬误记忆(≤τ_neg)存失败模式。Memory Manager过滤冗余。</p></div><div class="method-module"><h4>② 双阶段小样本PRM</h4><p>Stage 1: Step-level DPO。Stage 2: 5类分类（离散在few-shot下泛化更好）。Light-PRM(Qwen-3-4B)与Oracle(Gemini-2.5-Pro) EM一致。</p></div><div class="method-module"><h4>③ 全局共享并行搜索</h4><p>并发轨迹复用验证逻辑+规避已知错误→轨迹减55%性能反升。</p></div><h3>实验结果</h3><table><tr><th>方法</th><th>GPQA EM</th><th>MATH500</th><th>AIME25</th><th>轨迹↓</th></tr><tr><td>MCTS-RAG</td><td>64.65</td><td>80.60</td><td>50.00</td><td>18.76</td></tr><tr><td class="highlight">PRISM-MCTS</td><td class="highlight">65.08</td><td class="highlight">82.09</td><td class="highlight">53.33</td><td class="highlight">8.40</td></tr></table><h3>结论与启发</h3><p>"更聪明而非更用力"。记忆反思降55%搜索同时提升性能。</p></div>\n<div class="paper-card" id="p8"><div class="paper-title"><a href="https://arxiv.org/abs/2604.05087">Document Optimization for Black-Box Retrieval via RL</a></div><div class="paper-meta"><span>📅 2026-04-06 | <a href="https://arxiv.org/pdf/2604.05087">PDF</a></span><span>🏛 Stanford, OpenAI</span><span><span class="tag tag-rl">RL</span> <span class="tag">Retrieval</span></span></div><h3>背景与动机</h3><p>文档扩展应用于dense retriever反而引入噪声。用RL以黑盒检索排名变化作为奖励优化扩展文本。</p><h3>核心方法详解</h3><div class="method-module"><h4>① RL文档扩展</h4><p>LLM生成器追加文本，奖励=检索排名变化。PPO优化+对抗正则化防关键词填充。</p></div><h3>实验结果</h3><table><tr><th>方法</th><th>MS MARCO MRR@10</th><th>BEIR NDCG</th></tr><tr><td>无扩展</td><td>38.4</td><td>47.2</td></tr><tr><td class="highlight">RL-DocOpt</td><td class="highlight">41.7</td><td class="highlight">49.6</td></tr></table><h3>结论与启发</h3><p>首次RL优化黑盒检索器文档。可作RAG离线预处理，无查询时开销。</p></div>\n'

parts["part08_agent.html"] = '<h2 class="section-title agent">🤖 Agent — 智能体</h2>\n<div class="paper-card" id="p9"><div class="paper-title"><a href="https://arxiv.org/abs/2604.06126">Gym-Anything: Turn any Software into an Agent Environment</a></div><div class="paper-meta"><span>📅 2026-04-07 | <a href="https://arxiv.org/pdf/2604.06126">PDF</a></span><span>🏛 Multiple Institutions</span><span><span class="tag tag-agent">Agent</span> <span class="tag">Benchmark</span></span></div><h3>背景与动机</h3><p>Computer-use Agent受限于环境构建成本。Gym-Anything将任意软件自动转化为Gym兼容Agent环境。</p><h3>核心方法详解</h3><div class="method-module"><h4>① 自动环境封装</h4><p>截取UI渲染+系统API→观测(截图+可访问性树)+动作(鼠标/键盘+API)。</p></div><div class="method-module"><h4>② 任务自动生成</h4><p>LLM基于文档生成任务规范+奖励函数。69个软件2000+任务。</p></div><div class="method-module"><h4>③ 4级评估</h4><p>单步→多步→跨应用协作。</p></div><h3>实验结果</h3><table><tr><th>Agent</th><th>L1</th><th>L2</th><th>L3</th><th>L4</th></tr><tr><td>GPT-5.4+SoM</td><td class="highlight">72.3</td><td class="highlight">45.6</td><td class="highlight">28.1</td><td class="highlight">12.4</td></tr><tr><td>Claude Opus 4.6</td><td>68.9</td><td>41.2</td><td>24.7</td><td>9.8</td></tr></table><h3>结论与启发</h3><p>首个69+软件通用Agent框架。L4最佳仅12.4%，揭示巨大改进空间。</p></div>\n<div class="paper-card" id="p10"><div class="paper-title"><a href="https://arxiv.org/abs/2604.05477">Don\'t Act Blindly: Action-Effect Verification for GUI Agent</a></div><div class="paper-meta"><span>📅 2026-04-07 | <a href="https://arxiv.org/pdf/2604.05477">PDF</a></span><span>🏛 BIT, Baidu</span><span><span class="tag tag-agent">Agent</span> <span class="tag">GUI</span></span></div><h3>背景与动机</h3><p>GUI Agent操作后不验证→错误累积。AEV在每步后验证效果并自纠错。</p><h3>核心方法详解</h3><div class="method-module"><h4>① 动作效果预测</h4><p>轻量VLM预测预期效果并与实际对比。</p></div><div class="method-module"><h4>② 分层自纠错</h4><p>重试30%/替代路径45%/回退25%。</p></div><h3>实验结果</h3><table><tr><th>方法</th><th>AndroidWorld</th><th>WebArena</th></tr><tr><td>Baseline</td><td>24.3</td><td>18.7</td></tr><tr><td class="highlight">+AEV</td><td class="highlight">35.8(+11.5)</td><td class="highlight">27.4(+8.7)</td></tr></table><h3>结论与启发</h3><p>"先行动再验证"更实用。AEV是demo到生产的必要鲁棒性层。</p></div>\n'

parts["part09_medical.html"] = '<h2 class="section-title medical">⚕️ Medical — 医学LLM</h2>\n<div class="paper-card" id="p11"><div class="paper-title"><a href="https://arxiv.org/abs/2604.05081">MedGemma 1.5 Technical Report</a></div><div class="paper-meta"><span>📅 2026-04-06 | <a href="https://arxiv.org/pdf/2604.05081">PDF</a> | <a href="https://goo.gle/MedGemma">Resources</a></span><span>🏛 Google Research, Google DeepMind</span><span><span class="tag tag-medical">Medical</span> <span class="tag tag-whitelist">🏢 Google DeepMind</span></span></div><h3>背景与动机</h3><p>开放权重医学模型需覆盖3D放射(CT/MRI)、全玻片病理(WSI)等高维模态。MedGemma 1.5是首个4B参数内统一这些能力的开放模型。</p><h3>核心方法详解</h3><div class="method-module"><h4>① 3D体积处理</h4><p>CT/MRI→2D轴向切片(≤85片)。CT多通道窗宽：R(-1024,1024)全解剖、G(-135,215)软组织、B(0,80)脑实质。</p></div><div class="method-module"><h4>② WSI采样</h4><p>组织掩模→随机放大(5x/10x/20x)→896×896 patch(≤126)→保留空间排序。335K WSI-文本对。</p></div><div class="method-module"><h4>③ 蒸馏+RL后训练</h4><p>大教师256 logit蒸馏+领域教师+token级ROUGE-L RL。</p></div><h3>实验结果</h3><table><tr><th>任务</th><th>v1→v1.5</th><th>Δ</th></tr><tr><td>MedQA</td><td>64.4→<span class="highlight">69.1</span></td><td>+5</td></tr><tr><td>EHRQA</td><td>67.6→<span class="highlight">89.6</span></td><td>+22</td></tr><tr><td>3D MRI</td><td>51.3→<span class="highlight">64.7</span></td><td>+11</td></tr><tr><td>WSI ROUGE-L</td><td>2.2→<span class="highlight">49.4</span></td><td>+47</td></tr><tr><td>CXR IoU</td><td>3.1→<span class="highlight">38.0</span></td><td>+35</td></tr></table><h3>结论与启发</h3><p>4B可达多模态医学基线。WSI(+47)和CXR定位(+35)提升巨大。代价：通用知识略退(MMLU Pro -5.3)。</p></div>\n<div class="paper-card" id="p12"><div class="paper-title"><a href="https://arxiv.org/abs/2604.05051">LLM Sensitivity to Patient Question Framing in Medical QA</a></div><div class="paper-meta"><span>📅 2026-04-06 | <a href="https://arxiv.org/pdf/2604.05051">PDF</a></span><span>🏛 UC Berkeley</span><span><span class="tag tag-medical">Medical</span> <span class="tag">Robustness</span></span></div><h3>背景与动机</h3><p>患者问题含诱导性框架。LLM应不受措辞影响给出一致回答，但实际高度敏感。</p><h3>核心方法详解</h3><div class="method-module"><h4>① 5类框架</h4><p>中性/肯定引导/否定引导/情感诉求/权威引用。同一问题5种变体测一致性。</p></div><h3>实验结果</h3><table><tr><th>模型</th><th>中性Acc</th><th>一致性</th><th>最大偏差</th></tr><tr><td>GPT-5.4</td><td class="highlight">89.2</td><td class="highlight">0.82</td><td>12.3%</td></tr><tr><td>Llama-70B</td><td>72.1</td><td>0.63</td><td>28.7%</td></tr></table><h3>结论与启发</h3><p>肯定引导最易诱导过度乐观(偏差+8-15%)。医学AI需"去框架化"预处理。</p></div>\n'

parts["part10_mm_industry_footer.html"] = '<h2 class="section-title multimodal">🌐 Multimodal — 多模态</h2>\n<div class="paper-card" id="p13"><div class="paper-title"><a href="https://arxiv.org/abs/2604.05730">Controllable Image Generation with Composed Parallel Token Prediction</a></div><div class="paper-meta"><span>📅 2026-04-07 | <a href="https://arxiv.org/pdf/2604.05730">PDF</a></span><span>🏛 University of Oxford</span><span><span class="tag tag-multimodal">Multimodal</span> <span class="tag">Image Gen</span></span></div><h3>背景与动机</h3><p>自回归图像生成在可控性上受限。CPTP在自回归框架内实现多条件组合控制。</p><h3>核心方法详解</h3><div class="method-module"><h4>① 条件分解+并行预测</h4><p>各条件分支并行预测，乘积组合：\\(p(x_t|c_1,...,c_n) \\propto \\prod_i p(x_t|c_i)\\)。自适应权重动态调整。</p></div><h3>实验结果</h3><table><tr><th>方法</th><th>FID↓</th><th>CLIP↑</th><th>条件符合↑</th></tr><tr><td>LlamaGen</td><td>6.84</td><td>0.28</td><td>0.52</td></tr><tr><td class="highlight">CPTP</td><td class="highlight">5.92</td><td class="highlight">0.31</td><td class="highlight">0.78</td></tr></table><h3>结论与启发</h3><p>条件符合度+50%不牺牲质量。</p></div>\n<div class="paper-card" id="p14"><div class="paper-title"><a href="https://arxiv.org/abs/2604.05887">HybridKV: Hybrid KV Cache Compression for Multimodal LLM Inference</a></div><div class="paper-meta"><span>📅 2026-04-07 | <a href="https://arxiv.org/pdf/2604.05887">PDF</a></span><span>🏛 Zhejiang University, Alibaba</span><span><span class="tag tag-multimodal">Multimodal</span> <span class="tag">Efficiency</span></span></div><h3>背景与动机</h3><p>多模态LLM视觉token产生巨大KV缓存。现有压缩忽视视觉/文本注意力差异。</p><h3>核心方法详解</h3><div class="method-module"><h4>① 模态感知压缩</h4><p>视觉token(注意力均匀)→激进压缩；文本token(有锚点)→保守压缩。动态预算分配。</p></div><h3>实验结果</h3><table><tr><th>方法</th><th>显存节省</th><th>Video-MME</th><th>速度</th></tr><tr><td>Full KV</td><td>0%</td><td>62.3</td><td>1.0×</td></tr><tr><td class="highlight">HybridKV</td><td class="highlight">60%</td><td>61.8</td><td class="highlight">1.8×</td></tr></table><h3>结论与启发</h3><p>60%显存节省仅损0.5%性能。模态感知压缩是关键方向。</p></div>\n<h2 class="section-title industry">🏢 Industry Lab — 行业实验室</h2>\n<div class="paper-card" id="p15"><div class="paper-title"><a href="https://arxiv.org/abs/2604.05324">A Theoretical Framework for Statistical Evaluability of Generative Models</a></div><div class="paper-meta"><span>📅 2026-04-07 | <a href="https://arxiv.org/pdf/2604.05324">PDF</a></span><span>🏛 University of Maryland, Technion, Google Research</span><span><span class="tag tag-industry">Industry Lab</span> <span class="tag tag-whitelist">🏢 Google</span></span></div><h3>背景与动机</h3><p>生成模型评估缺乏理论保证。何时一个模型在统计意义上是"可评估的"？</p><h3>核心方法详解</h3><div class="method-module"><h4>① 可评估性形式化</h4><p>定义有限样本下统计可评估性条件，推导最小样本量理论下界，揭示维度灾难影响。</p></div><h3>结论与启发</h3><p>许多常用评估设置样本量严重不足，结论可能不可靠。为benchmarking提供理论基础。</p></div>\n<div class="reflection"><h2>📊 每日反思</h2><p>今日223篇new论文，精选15篇覆盖6板块。</p><p><strong>亮点</strong>：MegaTrain(单GPU训120B) · TPO(稀疏奖励大幅超越GRPO) · MedGemma 1.5(4B统一高维医学模态) · PRISM-MCTS(搜索轨迹↓55%) · π²(922样本显著提升长上下文推理)</p><p><strong>趋势</strong>：本周延续"效率优先"主题——训练效率(MegaTrain)、推理效率(PRISM-MCTS, HybridKV)、数据效率(π²)，都在用更少资源获更好效果。TPO代表RL方法论的重要简化。</p></div>\n<footer><p>arXiv AI 论文日报 · 2026-04-08 · 共抓取223篇new · 白名单扫描205篇命中6篇 · 精选15篇</p></footer>\n</body></html>'

# Write all parts
for name, content in sorted(parts.items()):
    path = f"{D}/{name}"
